<?php declare(strict_types=1); namespace App\Http\Controllers\Attendance; use App\Http\Controllers\Controller; use App\Http\Requests\Attendance\EmployeeAttendanceVerifyRequest; use App\Http\Requests\Attendance\EmployeeCheckInRequest; use App\Models\EmployeeAttendance; use App\Services\Attendance\EmployeeAttendanceService; use Illuminate\Http\RedirectResponse; use Illuminate\View\View;
class EmployeeAttendanceController extends Controller{public function mine():View{$employee=auth()->user()->employee;return view('attendance.employee.mine',['today'=>$employee?->attendances()->whereDate('attendance_date',now()->toDateString())->first(),'records'=>$employee?->attendances()->latest()->paginate(10)]);} public function checkIn(EmployeeCheckInRequest $r,EmployeeAttendanceService $s):RedirectResponse{$s->checkIn(auth()->user()->employee,$r->validated(),$r->file('selfie'));return back()->with('status','Check-in berhasil.');} public function checkOut(EmployeeAttendanceService $s):RedirectResponse{$a=auth()->user()->employee->attendances()->whereDate('attendance_date',now()->toDateString())->firstOrFail();$s->checkOut($a);return back()->with('status','Check-out berhasil.');} public function index():View{return view('attendance.employee.index',['records'=>EmployeeAttendance::with('employee')->filter(request()->only(['date','status','employee_id']))->latest()->paginate(15)]);} public function show(EmployeeAttendance $employeeAttendance):View{return view('attendance.employee.show',['record'=>$employeeAttendance->load('employee','verifier')]);} public function verify(EmployeeAttendanceVerifyRequest $r,EmployeeAttendance $employeeAttendance,EmployeeAttendanceService $s):RedirectResponse{$s->verify($employeeAttendance,$r->validated());return back()->with('status','Absensi terverifikasi.');}}
